import{_ as e,o as i,c as s,a2 as o}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Pipelines de datos","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/pipelines/01-introduccion.md","filePath":"data-engineering/pipelines/01-introduccion.md","lastUpdated":1782521464000}'),n={name:"data-engineering/pipelines/01-introduccion.md"};function r(t,a,l,d,c,p){return i(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="pipelines-de-datos" tabindex="-1">Pipelines de datos <a class="header-anchor" href="#pipelines-de-datos" aria-label="Permalink to &quot;Pipelines de datos&quot;">​</a></h1><p>Un pipeline de datos es una cadena de pasos que mueve datos desde una o varias fuentes hasta uno o varios destinos, aplicando controles, transformaciones y reglas operativas por el camino.</p><p>No es solo &quot;leer y escribir datos&quot;. Un buen pipeline define que se procesa, cuando, con que garantias, como se detectan errores, como se reprocesa y quien es responsable del resultado.</p><h2 id="capitulos" tabindex="-1">Capitulos <a class="header-anchor" href="#capitulos" aria-label="Permalink to &quot;Capitulos&quot;">​</a></h2><ol><li><a href="./01-introduccion">Introduccion</a></li><li><a href="./02-diseno-y-arquitectura">Diseno y arquitectura</a></li><li><a href="./03-batch-incremental-y-streaming">Batch, incremental y streaming</a></li><li><a href="./04-calidad-idempotencia-y-reprocesos">Calidad, idempotencia y reprocesos</a></li><li><a href="./05-observabilidad-y-operacion">Observabilidad y operacion</a></li><li><a href="./06-patrones-y-antipatrones">Patrones y antipatrones</a></li></ol><h2 id="que-problema-resuelven" tabindex="-1">Que problema resuelven <a class="header-anchor" href="#que-problema-resuelven" aria-label="Permalink to &quot;Que problema resuelven&quot;">​</a></h2><p>Los datos rara vez nacen en el sitio donde se consumen. Pueden venir de APIs, bases de datos, colas de eventos, ficheros, SaaS externos, logs o sensores. El pipeline conecta esos mundos y convierte entradas heterogeneas en datasets utiles, fiables y documentados.</p><p>Un pipeline suele resolver estas necesidades:</p><ul><li>Capturar datos desde una fuente.</li><li>Validar estructura, tipos y reglas minimas.</li><li>Enriquecer, limpiar o transformar informacion.</li><li>Guardar datos crudos antes de modificar nada.</li><li>Publicar datasets preparados para analisis, producto o ML.</li><li>Registrar metricas, errores y lineage.</li><li>Permitir reprocesos sin duplicar ni romper datos.</li></ul><h2 id="anatomia-basica" tabindex="-1">Anatomia basica <a class="header-anchor" href="#anatomia-basica" aria-label="Permalink to &quot;Anatomia basica&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fuente -&gt; ingesta -&gt; validacion -&gt; transformacion -&gt; almacenamiento -&gt; consumo -&gt; observabilidad</span></span></code></pre></div><p>Cada fase tiene una responsabilidad distinta:</p><ul><li><strong>Fuente:</strong> sistema origen, como PostgreSQL, una API REST, Kafka o ficheros SFTP.</li><li><strong>Ingesta:</strong> captura inicial y transporte hacia la plataforma de datos.</li><li><strong>Validacion:</strong> comprobacion de esquema, campos obligatorios, rangos y duplicados.</li><li><strong>Transformacion:</strong> limpieza, joins, agregaciones, reglas de negocio o normalizacion.</li><li><strong>Almacenamiento:</strong> data lake, data warehouse, base operacional o indice especializado.</li><li><strong>Consumo:</strong> BI, ciencia de datos, APIs, busquedas, aplicaciones o modelos de IA.</li><li><strong>Observabilidad:</strong> metricas, logs, alertas, lineage y runbooks.</li></ul><h2 id="capas-habituales" tabindex="-1">Capas habituales <a class="header-anchor" href="#capas-habituales" aria-label="Permalink to &quot;Capas habituales&quot;">​</a></h2><p>Una arquitectura sencilla suele separar los datos por nivel de elaboracion:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>raw -&gt; staging -&gt; curated -&gt; serving</span></span></code></pre></div><ul><li><strong>Raw:</strong> copia fiel de lo recibido. Es la red de seguridad para auditoria y reprocesos.</li><li><strong>Staging:</strong> datos parseados, tipados y con validaciones tecnicas.</li><li><strong>Curated:</strong> datos limpios con reglas de negocio aplicadas.</li><li><strong>Serving:</strong> modelos optimizados para consumo: dashboards, APIs, features o reportes.</li></ul><p>No todos los proyectos necesitan todas las capas desde el primer dia, pero separar datos crudos de datos transformados evita muchos problemas futuros.</p><h2 id="decisiones-iniciales" tabindex="-1">Decisiones iniciales <a class="header-anchor" href="#decisiones-iniciales" aria-label="Permalink to &quot;Decisiones iniciales&quot;">​</a></h2><p>Antes de construir, conviene responder:</p><ul><li>Que fuente manda los datos y con que frecuencia.</li><li>Si el pipeline sera batch, incremental, streaming o mixto.</li><li>Que identificador permite detectar duplicados.</li><li>Que contrato de esquema debe respetar la fuente.</li><li>Donde se guardaran los datos rechazados.</li><li>Que pasa si una ejecucion falla a medias.</li><li>Como se reprocesa un dia, una particion o un rango completo.</li><li>Que SLA tiene el dataset final.</li><li>Quien recibe la alerta si algo se rompe.</li></ul><h2 id="herramientas-relacionadas" tabindex="-1">Herramientas relacionadas <a class="header-anchor" href="#herramientas-relacionadas" aria-label="Permalink to &quot;Herramientas relacionadas&quot;">​</a></h2><p>Este manual habla del diseno transversal de pipelines. Otras herramientas cubren piezas concretas:</p><ul><li><a href="./../nifi/01-introduccion">Apache NiFi</a>: ingesta visual, routing y movimiento de datos.</li><li><a href="./../airflow/01-introduccion-y-arquitectura">Apache Airflow</a>: orquestacion de tareas y dependencias.</li><li><a href="./../spark/01-introduccion-a-apache-spark">Apache Spark</a>: procesamiento distribuido.</li><li><a href="./../kafka/01-introduccion-y-arquitectura">Kafka</a>: transporte de eventos y streaming.</li><li><a href="./../dbt/01-introduccion-y-proyecto">dbt</a>: modelado SQL, tests y documentacion en warehouses.</li><li><a href="./../../bases-de-datos/snowflake/01-introduccion-y-arquitectura">Snowflake</a>: almacenamiento analitico.</li><li><a href="./../delta-lake/01-introduccion-y-arquitectura">Delta Lake</a>: tablas ACID sobre data lakes.</li></ul><h2 id="ejemplo-rapido" tabindex="-1">Ejemplo rapido <a class="header-anchor" href="#ejemplo-rapido" aria-label="Permalink to &quot;Ejemplo rapido&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>API de ventas</span></span>
<span class="line"><span>  -&gt; ingesta incremental</span></span>
<span class="line"><span>  -&gt; validacion de esquema</span></span>
<span class="line"><span>  -&gt; raw/ventas</span></span>
<span class="line"><span>  -&gt; staging/ventas_tipadas</span></span>
<span class="line"><span>  -&gt; curated/fact_ventas</span></span>
<span class="line"><span>  -&gt; dashboard comercial</span></span></code></pre></div><p>Controles minimos:</p><ul><li>Guardar respuesta original o payload normalizado en raw.</li><li>Registrar fecha de extraccion y ventana procesada.</li><li>Validar campos obligatorios: id, fecha, importe y moneda.</li><li>Escribir errores en una zona de cuarentena.</li><li>Hacer la carga idempotente por <code>id_venta</code>.</li><li>Alertar si el numero de filas cae por debajo de lo esperado.</li></ul><h2 id="idea-clave" tabindex="-1">Idea clave <a class="header-anchor" href="#idea-clave" aria-label="Permalink to &quot;Idea clave&quot;">​</a></h2><p>Un pipeline fiable no se mide solo porque &quot;funciona hoy&quot;. Se mide porque se puede entender, observar, repetir y corregir cuando algo sale mal.</p>`,30)])])}const h=e(n,[["render",r]]);export{m as __pageData,h as default};
